mapper.select:
SELECT keyword_raw AS keyword, COUNT(*) AS searchCount, ROUND(AVG(result_count), 1) AS avgResultCount, ROUND( SUM(CASE WHEN matched_keyword_id IS NULL THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1 ) AS nullMatchRate FROM SEARCH_LOGS WHERE 1 = 1
AND TRUNC(search_at) >= #{startDate}
AND TRUNC(search_at) <= #{endDate}
GROUP BY keyword_raw ORDER BY COUNT(*) DESC FETCH FIRST #{topN} ROWS ONLY
